from flask import Flask, request, jsonify
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO, 
                    format='%(asctime)s - %(message)s')

# Dummy user data for authentication
users = {
    "user1": {"password": "password123", "email": "user1@example.com"},
    "user2": {"password": "password456", "email": "user2@example.com"}
}

def log_login_attempt(username, email, ip, user_agent, success):
    logging.info(f"Login attempt - Username: {username}, Email: {email}, IP: {ip}, User-Agent: {user_agent}, Success: {success}")

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    user_agent = request.headers.get('User-Agent')
    ip_address = request.remote_addr

    if username in users and users[username]['password'] == password:
        log_login_attempt(username, users[username]['email'], ip_address, user_agent, True)
        return jsonify({"message": "Login successful"}), 200
    else:
        log_login_attempt(username, data.get('email'), ip_address, user_agent, False)
        return jsonify({"message": "Invalid credentials"}), 401

if __name__ == '__main__':
    app.run(debug=True)